
html,body{
    margin: 0;
    padding: 0;
}
ul,li {
    margin: 0;
    padding: 0;
    list-style: none;
}
ul{
    height: 100%;
}
a {
    text-decoration: none;
}
#list {
    margin-top: 3.3rem;
    /*margin-bottom: 3rem;*/
}
#list a:link { 
    color:#000; 
    text-decoration:none;
}
#list a:visited { 
    color:#b2b2b2; 
    text-decoration:none;
}
#list a:hover { 
    color:#000; 
    text-decoration: none;
}
#list a:active { 
    color:#b2b2b2; 
    text-decoration:none;
}
#list li{
    padding: .5rem; 
    border-bottom: 1px solid #ccc;
    word-wrap: break-word;
}
#list li img {
    float: left;
    width: 5rem;
    height: 4.4rem;
}
#list .list-item{
    padding: .5rem; 
    margin-left: 5.5rem; 
    min-height: 4.4rem;
}
#list .list-item p{
    margin: 0;
    margin-bottom: .5rem;
    padding: 0;
    font-size: 1.1rem;
    font-weight: normal; 
    word-wrap: break-word;
    word-break: break-all;
}
#list .list-item h5{
    margin: 0;
    padding: 0;
    font-size: .8rem;
    font-weight: normal;
}
