
.wrap{
    width: 52px;
    height: 52px;
    -webkit-animation: animation-wrap 2.5s linear infinite;
            animation: animation-wrap 2.5s linear infinite;
}
/*外层布局*/
.circle-layout{
    width: 52px;
    height: 52px;
    -webkit-animation: animation-circle 3s cubic-bezier(0.4, 0, 0.2, 1) infinite;
            animation: animation-circle 3s cubic-bezier(0.4, 0, 0.2, 1) infinite;
}
/*左div*/
.layout-left{
    float: left;
    width: 50%;
    height: 100%;
    overflow: hidden;
    position: relative;
}
/*右div*/
.layout-right{
    float: right;
    width: 50%;
    height: 100%;
    overflow: hidden;
    position: relative;
}
