/*左圈动画*/
@-webkit-keyframes animation-circle-left{
0%{
        -webkit-transform: rotate(40deg);
                transform: rotate(40deg);
}
50%{
        -webkit-transform: rotate(-100deg);
                transform: rotate(-100deg);
}
100%{
        -webkit-transform: rotate(40deg);
                transform: rotate(40deg);
}
}
@keyframes animation-circle-left{
0%{
        -webkit-transform: rotate(40deg);
                transform: rotate(40deg);
}
50%{
        -webkit-transform: rotate(-100deg);
                transform: rotate(-100deg);
}
100%{
        -webkit-transform: rotate(40deg);
                transform: rotate(40deg);
}
}
/*右圈动画*/
@-webkit-keyframes animation-circle-right{
0%{
        -webkit-transform: rotate(-310deg);
                transform: rotate(-310deg);
}
50%{
        -webkit-transform: rotate(-170deg);
                transform: rotate(-170deg);
}
100%{
        -webkit-transform: rotate(-310deg);
                transform: rotate(-310deg);
}
}
@keyframes animation-circle-right{
0%{
        -webkit-transform: rotate(-310deg);
                transform: rotate(-310deg);
}
50%{
        -webkit-transform: rotate(-170deg);
                transform: rotate(-170deg);
}
100%{
        -webkit-transform: rotate(-310deg);
                transform: rotate(-310deg);
}
}
/*外层动画*/
@-webkit-keyframes animation-circle{
0%{
        -webkit-transform: rotate(0deg);
                transform: rotate(0deg);
}
25%{
        -webkit-transform: rotate(180deg);
                transform: rotate(180deg);
}
50%{
        -webkit-transform: rotate(360deg);
                transform: rotate(360deg);
}
75%{
        -webkit-transform: rotate(540deg);
                transform: rotate(540deg);
}
100%{
        -webkit-transform: rotate(720deg);
                transform: rotate(720deg);
}
}
@keyframes animation-circle{
0%{
        -webkit-transform: rotate(0deg);
                transform: rotate(0deg);
}
25%{
        -webkit-transform: rotate(180deg);
                transform: rotate(180deg);
}
50%{
        -webkit-transform: rotate(360deg);
                transform: rotate(360deg);
}
75%{
        -webkit-transform: rotate(540deg);
                transform: rotate(540deg);
}
100%{
        -webkit-transform: rotate(720deg);
                transform: rotate(720deg);
}
}
/*最外层动画*/
@-webkit-keyframes animation-wrap{
0%{
        -webkit-transform: rotate(0deg);
                transform: rotate(0deg);
}
100%{
        -webkit-transform: rotate(360deg);
                transform: rotate(360deg);
}
}
@keyframes animation-wrap{
0%{
        -webkit-transform: rotate(0deg);
                transform: rotate(0deg);
}
100%{
        -webkit-transform: rotate(360deg);
                transform: rotate(360deg);
}
}



