
#user {
    margin-top: 3.3rem;
    margin-bottom: 3rem;
}
#user li{
    padding: .5rem; 
    border-bottom: 1px solid #ccc;
    word-wrap: break-word;
}
#user li img{
    width: 10rem;
    height: 8rem;
}
#user .list-item{
    padding: .5rem; 
    min-height: 4.4rem;
}
#user .list-item p{
    margin: 0;
    margin-bottom: .5rem;
    padding: 0;
    font-size: 1.1rem;
    font-weight: normal; 
    word-wrap: break-word;
    word-break: break-all;
}
#user .list-item h5{
    margin: 0;
    padding: 0;
    font-size: .8rem;
    font-weight: normal;
}
#user .user-topic-list {
    border-bottom: 1px solid #ccc;
    color: #65bbce;
    /*text-shadow: 4px 2px 4px #480b0b;*/
}
#user .login-btn{
    display: inline-block;
    margin: 1rem 1rem 0;
    background: #65bbce;
    color: #fff;
    font-size: 1.2rem;
    text-align: center;
    line-height: 2.6rem;
    width: 7rem;
    height: 2.6rem;
    border-radius: .5rem;
    border: none;
    vertical-align: top;
}
#user a:link { 
    color:#000; 
    text-decoration:none;
}
#user a:visited { 
    color:#b2b2b2; 
    text-decoration:none;
}
#user a:hover { 
    color:#000; 
    text-decoration: none;
}
#user a:active { 
    color:#b2b2b2; 
    text-decoration:none;
} 






