
#publish .publish-from {
    display: block;
    margin-top: 3.3rem;
    width: 100%;
    height: 100%;
}
#publish .publish-from img{
    display: block;
    margin: 5rem auto 0;
}
#publish .publish-from div{
    text-align: center;
}
#editor {
	display: block;
    margin-top: 3.3rem;
    width: 100%;
    height: 100%;
}
#editor .login-text{
    display: block;
    margin: 3.5rem auto .5rem;
    width: 90%;
    font-size: 1.2rem;
    height: 2.6rem;
    border: none;
    border-bottom: 1px solid #ccc;
}
#editor .login-btn{
    display: block;
    margin: 1rem auto 0;
    background: #65bbce;
    color: #fff;
    font-size: 1.2rem;
    text-align: center;
    line-height: 2.6rem;
    width: 70%;
    height: 2.6rem;
    border-radius: .5rem;
    border: none;
}
.w-e-toolbar { display: block !important;
}
.w-e-toolbar .w-e-menu {  display: inline-block !important;
}
.w-e-text-container { height: 400px !important;
}




